import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import API from "../../api/api";

const fmt = (d) =>
  d ? new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" }) : "";

const statusConfig = {
  submitted: { bg: "#eff6ff", color: "#1e40af", border: "#bfdbfe", dot: "#3b82f6", label: "Submitted"    },
  approved:  { bg: "#f0fdf4", color: "#15803d", border: "#86efac", dot: "#22c55e", label: "Approved"     },
  revision:  { bg: "#fff7ed", color: "#c2410c", border: "#fed7aa", dot: "#f97316", label: "Needs Revision"},
};

/* ── SVG icons ── */
const IconGithub = () => (
  <svg width="15" height="15" fill="none" stroke="currentColor" strokeWidth="1.8" viewBox="0 0 24 24">
    <path d="M9 19c-5 1.5-5-2.5-7-3m14 6v-3.87a3.37 3.37 0 00-.94-2.61c3.14-.35 6.44-1.54 6.44-7A5.44 5.44 0 0020 4.77 5.07 5.07 0 0019.91 1S18.73.65 16 2.48a13.38 13.38 0 00-7 0C6.27.65 5.09 1 5.09 1A5.07 5.07 0 005 4.77a5.44 5.44 0 00-1.5 3.78c0 5.42 3.3 6.61 6.44 7A3.37 3.37 0 009 18.13V22"/>
  </svg>
);
const IconExternal = () => (
  <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
    <path d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/>
  </svg>
);
const IconCheck = () => (
  <svg width="15" height="15" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24">
    <path d="M5 13l4 4L19 7"/>
  </svg>
);
const IconRevision = () => (
  <svg width="15" height="15" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
    <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"/>
  </svg>
);
const IconBack = () => (
  <svg width="15" height="15" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
    <path d="M15 18l-6-6 6-6"/>
  </svg>
);
const IconDoc = () => (
  <svg width="15" height="15" fill="none" stroke="#14b8a6" strokeWidth="1.8" viewBox="0 0 24 24">
    <path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414A1 1 0 0119 9.414V19a2 2 0 01-2 2z"/>
  </svg>
);

export default function Submissions() {
  const { projectId } = useParams();
  const navigate = useNavigate();

  const [submissions, setSubmissions] = useState([]);
  const [project, setProject]         = useState(null);
  const [loading, setLoading]         = useState(true);
  const [feedback, setFeedback]       = useState({});   // { [id]: string }
  const [acting, setActing]           = useState({});   // { [id]: bool }
  const [toast, setToast]             = useState("");

  useEffect(() => {
    API.get(`/submissions/project/${projectId}`)
      .then((res) => {
        const data = res.data || [];
        setSubmissions(data);
        if (data.length > 0 && data[0].project_title) {
          setProject({ title: data[0].project_title });
        }
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [projectId]);

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(""), 3000);
  };

  const act = async (subId, status) => {
    setActing((a) => ({ ...a, [subId]: true }));
    try {
      await API.put(`/submissions/${subId}/status`, {
        status,
        feedback: feedback[subId] || "",
      });
      setSubmissions((prev) =>
        prev.map((s) =>
          s.id === subId
            ? { ...s, status, feedback: feedback[subId] || s.feedback }
            : s
        )
      );
      showToast(status === "approved" ? "✓ Submission approved!" : "↺ Revision requested");
    } catch (e) {
      showToast("Something went wrong. Please try again.");
    }
    setActing((a) => ({ ...a, [subId]: false }));
  };

  const initials = (name) =>
    name?.split(" ").map((n) => n[0]).join("").toUpperCase().slice(0, 2) || "?";

  if (loading) return (
    <div style={s.loadWrap}><div style={s.spinner} /></div>
  );

  return (
    <div style={s.page}>

      {/* Toast */}
      {toast && (
        <div style={s.toast}>
          <IconCheck /> {toast}
        </div>
      )}

      {/* Header */}
      <button onClick={() => navigate("/client/my-projects")} style={s.backBtn}>
        <IconBack /> Back to Projects
      </button>

      <div style={s.headerRow}>
        <div>
          <p style={s.overline}>SUBMISSIONS</p>
          <h1 style={s.title}>Work Submissions</h1>
          {project && (
            <p style={s.subtitle}>
              Project: <strong style={{ color: "#0f172a" }}>{project.title}</strong>
            </p>
          )}
        </div>
        <div style={s.countBadge}>
          <IconDoc />
          {submissions.length} submission{submissions.length !== 1 ? "s" : ""}
        </div>
      </div>

      {/* Empty */}
      {submissions.length === 0 ? (
        <div style={s.emptyCard}>
          <svg width="44" height="44" fill="none" stroke="#cbd5e1" strokeWidth="1.5" viewBox="0 0 24 24">
            <path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414A1 1 0 0119 9.414V19a2 2 0 01-2 2z"/>
          </svg>
          <p style={{ color: "#94a3b8", fontSize: 14, marginTop: 12 }}>No submissions yet for this project.</p>
        </div>
      ) : (
        <div style={s.list}>
          {submissions.map((sub) => {
            const st  = statusConfig[sub.status] || statusConfig.submitted;
            const isActing = acting[sub.id];
            const alreadyDone = sub.status === "approved";

            return (
              <div key={sub.id} style={s.card}>

                {/* Card header row */}
                <div style={s.cardHeader}>
                  <div style={s.freelancerRow}>
                    {/* Avatar */}
                    <div style={{ ...s.avatar, background: "#0f766e" }}>
                      {initials(sub.freelancer_name)}
                    </div>
                    <div>
                      <p style={s.freelancerName}>{sub.freelancer_name}</p>
                      <p style={s.submittedAt}>Submitted: {fmt(sub.created_at)}</p>
                    </div>
                  </div>
                  {/* Status badge */}
                  <span style={{ ...s.statusBadge, background: st.bg, color: st.color, border: `1px solid ${st.border}` }}>
                    <span style={{ ...s.dot, background: st.dot }} />
                    {st.label}
                  </span>
                </div>

                {/* Work description */}
                <div style={s.descBox}>
                  <p style={s.descLabel}>Work Description</p>
                  <p style={s.descText}>{sub.description}</p>
                </div>

                {/* Links */}
                {(sub.github_link || sub.live_link) && (
                  <div style={s.linkRow}>
                    {sub.github_link && (
                      <a href={sub.github_link} target="_blank" rel="noreferrer" style={s.linkBtn}>
                        <IconGithub /> GitHub Repository
                      </a>
                    )}
                    {sub.live_link && (
                      <a href={sub.live_link} target="_blank" rel="noreferrer" style={{ ...s.linkBtn, ...s.linkBtnTeal }}>
                        <IconExternal /> Live Demo
                      </a>
                    )}
                  </div>
                )}

                {/* Previous feedback (if any) */}
                {sub.feedback && sub.status === "revision" && (
                  <div style={s.prevFeedback}>
                    <p style={s.prevFeedbackLabel}>Your previous feedback</p>
                    <p style={s.prevFeedbackText}>{sub.feedback}</p>
                  </div>
                )}

                {/* Action section — hide if approved */}
                {!alreadyDone && (
                  <div style={s.actionSection}>
                    <div style={s.feedbackBlock}>
                      <label style={s.feedbackLabel}>
                        Feedback
                        <span style={s.feedbackHint}> (optional — required for revision)</span>
                      </label>
                      <textarea
                        value={feedback[sub.id] || ""}
                        onChange={(e) => setFeedback((f) => ({ ...f, [sub.id]: e.target.value }))}
                        placeholder="Tell the freelancer what needs to be changed..."
                        style={s.textarea}
                        rows={3}
                      />
                    </div>

                    <div style={s.btnRow}>
                      {/* Approve */}
                      <button
                        onClick={() => act(sub.id, "approved")}
                        disabled={isActing}
                        style={{ ...s.approveBtn, opacity: isActing ? 0.7 : 1 }}
                      >
                        {isActing ? <div style={s.btnSpinner} /> : <IconCheck />}
                        Approve Work
                      </button>

                      {/* Request Revision */}
                      <button
                        onClick={() => {
                          if (!feedback[sub.id]?.trim()) {
                            setFeedback((f) => ({ ...f, [sub.id]: f[sub.id] || "" }));
                            showToast("Please add feedback before requesting a revision.");
                            return;
                          }
                          act(sub.id, "revision");
                        }}
                        disabled={isActing}
                        style={{ ...s.revisionBtn, opacity: isActing ? 0.7 : 1 }}
                      >
                        {isActing ? <div style={{ ...s.btnSpinner, borderTopColor: "#ea580c" }} /> : <IconRevision />}
                        Request Revision
                      </button>
                    </div>
                  </div>
                )}

                {/* Approved state */}
                {alreadyDone && (
                  <div style={s.approvedBanner}>
                    <IconCheck />
                    This submission has been approved. Great work!
                  </div>
                )}

              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

const s = {
  page: {
    background: "#f8fafc", minHeight: "100vh",
    padding: "32px 40px", fontFamily: "'Inter', 'Segoe UI', sans-serif",
  },
  loadWrap: {
    background: "#f8fafc", minHeight: "100vh",
    display: "flex", alignItems: "center", justifyContent: "center",
  },
  spinner: {
    width: 32, height: 32, borderRadius: "50%",
    border: "3px solid #e2e8f0", borderTopColor: "#14b8a6",
  },

  /* toast */
  toast: {
    position: "fixed", top: 20, right: 24,
    background: "#065f46", color: "white",
    padding: "11px 18px", borderRadius: 10,
    fontSize: 13, fontWeight: 600,
    display: "flex", alignItems: "center", gap: 8,
    boxShadow: "0 8px 24px rgba(0,0,0,0.15)", zIndex: 200,
  },

  /* back */
  backBtn: {
    display: "inline-flex", alignItems: "center", gap: 6,
    fontSize: 13, fontWeight: 600, color: "#64748b",
    background: "transparent", border: "none", cursor: "pointer",
    padding: "0 0 20px", marginBottom: 0,
  },

  /* header */
  headerRow: {
    display: "flex", justifyContent: "space-between",
    alignItems: "flex-start", marginBottom: 28,
  },
  overline: {
    fontSize: 11, fontWeight: 700, color: "#94a3b8",
    letterSpacing: "1.5px", textTransform: "uppercase", margin: "0 0 6px",
  },
  title: {
    fontSize: 26, fontWeight: 700, color: "#0f172a",
    margin: "0 0 4px", letterSpacing: "-0.5px",
  },
  subtitle: { fontSize: 14, color: "#64748b", margin: 0 },
  countBadge: {
    display: "flex", alignItems: "center", gap: 7,
    background: "#f0fdfa", border: "1px solid #99f6e4",
    borderRadius: 8, padding: "8px 14px",
    fontSize: 13, fontWeight: 600, color: "#0f766e", flexShrink: 0,
  },

  /* empty */
  emptyCard: {
    background: "white", border: "1px solid #e2e8f0",
    borderRadius: 14, padding: "64px 24px", textAlign: "center",
    display: "flex", flexDirection: "column", alignItems: "center",
  },

  /* list */
  list: { display: "flex", flexDirection: "column", gap: 16 },

  /* card */
  card: {
    background: "white", border: "1px solid #e2e8f0",
    borderRadius: 14, padding: "24px",
    boxShadow: "0 1px 4px rgba(0,0,0,0.05)",
  },

  /* card header */
  cardHeader: {
    display: "flex", justifyContent: "space-between",
    alignItems: "flex-start", marginBottom: 18,
  },
  freelancerRow: { display: "flex", alignItems: "center", gap: 12 },
  avatar: {
    width: 42, height: 42, borderRadius: "50%",
    display: "flex", alignItems: "center", justifyContent: "center",
    fontSize: 14, fontWeight: 800, color: "white", flexShrink: 0,
  },
  freelancerName: { fontSize: 15, fontWeight: 700, color: "#0f172a", margin: "0 0 2px" },
  submittedAt:   { fontSize: 12, color: "#94a3b8", margin: 0 },
  statusBadge: {
    display: "inline-flex", alignItems: "center", gap: 6,
    padding: "5px 12px", borderRadius: 20, fontSize: 12, fontWeight: 700,
  },
  dot: { width: 7, height: 7, borderRadius: "50%", flexShrink: 0 },

  /* description */
